The pattern: read the sensor in loop(), push to datastreams. Host subscribes via `device.datastream('temperature').subscribe()`.

```cpp
#include <Wire.h>
#include <Adafruit_BME280.h>
#include <Conduyt.h>

const uint8_t BME_ADDR = 0x76;
Adafruit_BME280 bme;

ConduytSerial transport(Serial, 115200);
ConduytDevice device("BMENode", "1.0.0", transport);

uint32_t lastPush = 0;

void setup() {
  Wire.begin(8, 9);
  if (!bme.begin(BME_ADDR)) {
    Serial.println("BME280 not found");
  }
  device.addDatastream("temperature", CONDUYT_FLOAT32, "celsius", false);
  device.addDatastream("humidity",    CONDUYT_FLOAT32, "percent", false);
  device.begin();
}

void loop() {
  device.poll();
  if (millis() - lastPush >= 2000) {
    lastPush = millis();
    device.writeDatastream("temperature", bme.readTemperature());
    device.writeDatastream("humidity",    bme.readHumidity());
  }
}
```

`ConduytBLE` transport on ESP32 wraps the NimBLE stack. The advertising name is whatever the central will see.

```cpp
#include <Conduyt.h>
#include <conduyt/transport/ConduytBLE.h>

const int LED_PIN = 13;

ConduytBLE    transport("CONDUYT-Sensor");
ConduytDevice device("BleSensor", "1.0.0", transport);

void onLed(ConduytPayloadReader &p, ConduytContext &ctx) {
  bool on = p.readBool();
  digitalWrite(LED_PIN, on ? HIGH : LOW);
  ctx.ack();
}

void setup() {
  pinMode(LED_PIN, OUTPUT);
  device.addDatastream("led", CONDUYT_BOOL, "", true);
  device.onDatastreamWrite("led", onLed);
  device.begin();
}

void loop() {
  device.poll();
}
```

WebSerial requires a user gesture to call `navigator.serial.requestPort()`. Wire the click to a button.

```ts
import { ConduytDevice } from 'conduyt-js'
import { WebSerialTransport } from 'conduyt-js/transports/web-serial'

const tempEl = document.querySelector<HTMLElement>('#temp')!
const connectBtn = document.querySelector<HTMLButtonElement>('#connect')!

connectBtn.addEventListener('click', async () => {
  const port = await navigator.serial.requestPort()
  await port.open({ baudRate: 115200 })

  const device = await ConduytDevice.connect(
    new WebSerialTransport({ port })
  )

  for await (const v of device.datastream('temperature').subscribe()) {
    tempEl.textContent = `${v.toFixed(2)} C`
  }
})
```

Node BLE bindings (`@abandonware/noble` family) need root or capabilities on Linux. The transport wraps that.

```ts
import { ConduytDevice } from 'conduyt-js'
import { BLETransport } from 'conduyt-js/transports/ble'
import { ConduytServo } from 'conduyt-js/modules/servo'

const device = await ConduytDevice.connect(
  new BLETransport({ name: 'CONDUYT-Servo' })
)

const servo = new ConduytServo(device)
await servo.attach(9)

for (let angle = 0; angle <= 180; angle += 10) {
  await servo.write(angle)
  await new Promise((r) => setTimeout(r, 100))
}

await device.disconnect()
```

`ConduytMQTT` takes a network client, broker host/port, and a client/topic id. Conduyt mangles its protocol into MQTT topics under that prefix.

```cpp
#include <WiFi.h>
#define CONDUYT_TRANSPORT_MQTT
#include <Conduyt.h>
#include <conduyt/transport/ConduytMQTT.h>

const char* WIFI_SSID = "your-ssid";
const char* WIFI_PASS = "your-password";
const char* BROKER    = "mqtt.local";
const uint16_t PORT   = 1883;

WiFiClient    wifi;
ConduytMQTT   transport(wifi, BROKER, PORT, "lab/sensor1");
ConduytDevice device("HumNode", "1.0.0", transport);

uint32_t lastPush = 0;

void setup() {
  WiFi.begin(WIFI_SSID, WIFI_PASS);
  while (WiFi.status() != WL_CONNECTED) delay(250);

  device.addDatastream("humidity", CONDUYT_FLOAT32, "percent", false);
  device.begin();
}

void loop() {
  device.poll();
  if (millis() - lastPush >= 5000) {
    lastPush = millis();
    device.writeDatastream("humidity", 50.0f + (millis() % 10000) / 1000.0f);
  }
}
```

Multiple module enable macros, all before the Conduyt include.

```cpp
#define CONDUYT_MODULE_SERVO
#define CONDUYT_MODULE_NEOPIXEL
#include <Conduyt.h>

ConduytSerial transport(Serial, 115200);
ConduytDevice device("Combo", "1.0.0", transport);

uint8_t mode = 0;

void onMode(ConduytPayloadReader &p, ConduytContext &ctx) {
  mode = p.readUInt8();
  ctx.ack();
}

void setup() {
  device.addModule(new ConduytModuleServo());
  device.addModule(new ConduytModuleNeoPixel());
  device.addDatastream("mode", CONDUYT_UINT8, "", true);
  device.onDatastreamWrite("mode", onMode);
  device.begin();
}

void loop() {
  device.poll();
  // mode-driven animation hooks would live here
}
```

`ReconnectTransport` retries on disconnect with exponential backoff.

```ts
import { ConduytDevice, ReconnectTransport } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const transport = new ReconnectTransport(
  new SerialTransport({ path: '/dev/ttyACM0' }),
  { initialDelayMs: 250, maxDelayMs: 5000 }
)

const device = await ConduytDevice.connect(transport)

device.on('disconnect', () => console.warn('disconnected; will reconnect'))
device.on('reconnect',  () => console.log('reconnected'))

for await (const t of device.datastream('temperature').subscribe()) {
  console.log(t)
}
```

`ConduytOLED` covers SSD1306 panels; the firmware must enable `CONDUYT_MODULE_OLED` and have an SSD1306 wired up.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytOLED } from 'conduyt-js/modules/oled'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const oled = new ConduytOLED(device)
await oled.begin({ width: 128, height: 64, address: 0x3C })

for await (const t of device.datastream('temperature').subscribe()) {
  await oled.clear()
  await oled.text(0, 24, `T = ${t.toFixed(1)} C`, { size: 2 })
  await oled.show()
}
```

Polling at high rate but only writing on edge keeps the wire quiet.

```cpp
#include <Conduyt.h>

const int BTN_PIN = 0;

ConduytSerial transport(Serial, 115200);
ConduytDevice device("BtnNode", "1.0.0", transport);

bool lastState = true;

void setup() {
  pinMode(BTN_PIN, INPUT_PULLUP);
  device.addDatastream("button", CONDUYT_BOOL, "", false);
  device.begin();
}

void loop() {
  device.poll();
  bool now = digitalRead(BTN_PIN);
  if (now != lastState) {
    lastState = now;
    device.writeDatastream("button", now == LOW);
  }
}
```
